# --- ID3D10Blob methods ---

proc getBufferPointer*(self: ID3D10Blob): pointer =
  type F = proc(this: ID3D10Blob): pointer {.stdcall.}
  callVtbl0(self, 3, F)

proc getBufferSize*(self: ID3D10Blob): csize_t =
  type F = proc(this: ID3D10Blob): csize_t {.stdcall.}
  callVtbl0(self, 4, F)

# --- ID3DDestructionNotifier methods ---

proc registerDestructionCallback*(self: ID3DDestructionNotifier, callback_func: pointer, data: pointer, callback_id: ptr uint32) =
  type F = proc(this: ID3DDestructionNotifier, callback_func: pointer, data: pointer, callback_id: ptr uint32): int32 {.stdcall.}
  callVtblErr(self, 3, F, "ID3DDestructionNotifier.RegisterDestructionCallback", callback_func, data, callback_id)

proc unregisterDestructionCallback*(self: ID3DDestructionNotifier, callback_id: uint32) =
  type F = proc(this: ID3DDestructionNotifier, callback_id: uint32): int32 {.stdcall.}
  callVtblErr(self, 4, F, "ID3DDestructionNotifier.UnregisterDestructionCallback", callback_id)

# --- ID3DInclude methods ---

proc open*(self: ID3DInclude, include_type: uint32, filename: cstring, parent_data: pointer, data: pointer, bytes: ptr uint32) =
  type F = proc(this: ID3DInclude, include_type: uint32, filename: cstring, parent_data: pointer, data: pointer, bytes: ptr uint32): int32 {.stdcall.}
  callVtblErr(self, 3, F, "ID3DInclude.Open", include_type, filename, parent_data, data, bytes)

proc close*(self: ID3DInclude, data: pointer) =
  type F = proc(this: ID3DInclude, data: pointer): int32 {.stdcall.}
  callVtblErr(self, 4, F, "ID3DInclude.Close", data)

